// Stub type definitions to enable compilation of hand-written msgs.go
// These are normally generated by protoc/buf from governance.proto

package types

import (
	"time"

	"cosmossdk.io/math"
	sdk "github.com/cosmos/cosmos-sdk/types"
	anyproto "github.com/cosmos/gogoproto/types/any"
)

// VoteOption is an enum representing a vote option
type VoteOption int32

const (
	VoteOption_VOTE_OPTION_UNSPECIFIED  VoteOption = 0
	VoteOption_VOTE_OPTION_YES          VoteOption = 1
	VoteOption_VOTE_OPTION_NO           VoteOption = 2
	VoteOption_VOTE_OPTION_NO_WITH_VETO VoteOption = 3
	VoteOption_VOTE_OPTION_ABSTAIN      VoteOption = 4
)

// ProposalStatus is an enum representing the status of a proposal
type ProposalStatus int32

const (
	ProposalStatus_PROPOSAL_STATUS_UNSPECIFIED    ProposalStatus = 0
	ProposalStatus_PROPOSAL_STATUS_DEPOSIT_PERIOD ProposalStatus = 1
	ProposalStatus_PROPOSAL_STATUS_VOTING_PERIOD  ProposalStatus = 2
	ProposalStatus_PROPOSAL_STATUS_PASSED         ProposalStatus = 3
	ProposalStatus_PROPOSAL_STATUS_REJECTED       ProposalStatus = 4
	ProposalStatus_PROPOSAL_STATUS_FAILED         ProposalStatus = 5
)

// MsgSubmitProposal is a governance proposal submission message
type MsgSubmitProposal struct {
	Messages       []*anyproto.Any
	InitialDeposit sdk.Coins
	Proposer       string
	Metadata       string
	Title          string
	Summary        string
	Expedited      bool
}

// MsgVote is a governance voting message
type MsgVote struct {
	ProposalId uint64
	Voter      string
	Option     VoteOption
	Metadata   string
}

// MsgVoteWeighted is a governance weighted voting message
type MsgVoteWeighted struct {
	ProposalId      uint64
	Voter           string
	WeightedOptions []WeightedVoteOption
	Metadata        string
}

// WeightedVoteOption represents a vote option with a weight
type WeightedVoteOption struct {
	Option VoteOption
	Weight math.LegacyDec
}

// MsgDeposit is a governance deposit message
type MsgDeposit struct {
	ProposalId uint64
	Depositor  string
	Amount     sdk.Coins
}

// MsgUpdateParams is a governance params update message
type MsgUpdateParams struct {
	Authority string
	Params    Params
}

// Params represents governance module parameters
type Params struct {
	MinDeposit               sdk.Coins
	MaxDepositPeriod         time.Duration
	VotingPeriod             time.Duration
	QuorumPercent            string
	ThresholdPercent         string
	VetoThresholdPercent     string
	MinInitialDepositRatio   string
	ProposalCancelRatio      string
	ProposalCancelDest       string
	ExpediteThresholdPercent string
	ExpediteMinDeposit       sdk.Coins
}
